blocks.body:
{
    "level": "B1–B2",
    "intro": "W tym temacie dowiesz się, które <strong>czasowniki NIE MOGĄ tworzyć strony biernej</strong> i dlaczego. Jest to ważne, aby uniknąć błędów gramatycznych.",
    "rules": [
        {
            "label": "Nieprzechodni",
            "color": "rose",
            "text": "<strong>Czasowniki nieprzechodnie</strong> (bez dopełnienia) — bez strony biernej:",
            "example": "He arrived. ✅ (не: He was arrived. ❌)"
        },
        {
            "label": "Czasowniki stanu",
            "color": "amber",
            "text": "Niektóre <strong>czasowniki statywne</strong> nie mają strony biernej:",
            "example": "I have a car. ✅ (не: A car is had by me. ❌)"
        },
        {
            "label": "Odwracać",
            "color": "blue",
            "text": "<strong>Czasowniki odwrotne</strong> — bez strony biernej:",
            "example": "She washed herself. ✅ (не: Herself was washed. ❌)"
        }
    ]
}

{
    "title": "1. Czasowniki nieprzechodnie",
    "intro": "Czasowniki bez dopełnienia bliższego <strong>nie tworzą strony biernej</strong>:",
    "items": [
        {
            "label": "przyjechać",
            "title": "przyjechać",
            "subtitle": "Przybył. ✅ (не: przybył ❌)"
        },
        {
            "label": "Iść",
            "title": "iść",
            "subtitle": "Poszli do domu. ✅ (не: Domu nie było ❌)"
        },
        {
            "label": "przychodzić",
            "title": "przychodzić",
            "subtitle": "Przyszła wcześnie. ✅ (bez pasywnego)"
        },
        {
            "label": "spać",
            "title": "spać",
            "subtitle": "Spał dobrze. ✅ (bez pasywnego)"
        },
        {
            "label": "umierać",
            "title": "umrzeć",
            "subtitle": "Król zmarł. ✅ (bez pasywnego)"
        },
        {
            "label": "stać się",
            "title": "zdarzać się",
            "subtitle": "To wydarzyło się wczoraj. ✅ (bez pasywnego)"
        },
        {
            "label": "istnieć",
            "title": "istnieć",
            "subtitle": "Istnieją problemy. ✅ (bez pasywnego)"
        },
        {
            "label": "pojawić się",
            "title": "pojawić się",
            "subtitle": "Pojawił się duch. ✅ (bez pasywnego)"
        }
    ]
}

{
    "title": "2. Czasowniki statywne",
    "sections": [
        {
            "label": "Posiadanie",
            "color": "rose",
            "description": "Czasowniki <strong>posiadanie</strong> zwykle nie zawierają strony biernej:",
            "examples": [
                {
                    "en": "I have a car. ✅",
                    "ua": "(не: Mam samochód. ❌)"
                },
                {
                    "en": "She owns a house. ✅",
                    "ua": "(nie: dom jest jej własnością. ❌ — rzadko)"
                },
                {
                    "en": "They possess great wealth. ✅",
                    "ua": "(zwykle nie w stronie biernej)"
                }
            ]
        },
        {
            "label": "Konformizm",
            "color": "amber",
            "description": "Czasowniki określające <strong>zgodność i podobieństwo</strong>:",
            "examples": [
                {
                    "en": "The dress fits her. ✅",
                    "ua": "(не: Jest dopasowana przez sukienkę. ❌)"
                },
                {
                    "en": "This shirt suits you. ✅",
                    "ua": "(не: Pasuje Ci ta koszula. ❌)"
                },
                {
                    "en": "The key fits the lock. ✅",
                    "ua": "(bez pasywnego)"
                }
            ]
        },
        {
            "label": "Treść / treść",
            "color": "blue",
            "description": "Czasowniki określające <strong>pojemność</strong>:",
            "examples": [
                {
                    "en": "The hall holds 500 people. ✅",
                    "ua": "(не: W sali przetrzymywanych jest 500 osób. ❌)"
                },
                {
                    "en": "The bottle contains water. ✅",
                    "ua": "(не: Butelka zawiera wodę. ❌)"
                },
                {
                    "en": "The bag weighs 5 kg. ✅",
                    "ua": "(zwykle nie w stronie biernej)"
                }
            ]
        },
        {
            "label": "Wzajemność",
            "color": "emerald",
            "description": "Niektóre <strong>czasowniki wzajemne</strong>:",
            "examples": [
                {
                    "en": "Tom resembles his father. ✅",
                    "ua": "(не: Jego ojciec jest podobny do Toma. ❌)"
                },
                {
                    "en": "This equals that. ✅",
                    "ua": "(zwykle nie w stronie biernej)"
                },
                {
                    "en": "They lack experience. ✅",
                    "ua": "(не: Brakuje doświadczenia. ❌)"
                }
            ]
        }
    ]
}

{
    "title": "3. Czasowniki przechodnie i nieprzechodnie",
    "intro": "Tylko <strong>czasowniki przechodnie</strong> (z dopełnieniem bezpośrednim) tworzą stronę bierną:",
    "rows": [
        {
            "en": "Transitive: They wrote a letter.",
            "ua": "Napisali list.",
            "note": "→ Passive: A letter was written. ✅"
        },
        {
            "en": "Intransitive: He arrived late.",
            "ua": "Przyjechał późno.",
            "note": "→ Pasywnie: ❌ (bez aplikacji)"
        },
        {
            "en": "Transitive: She opened the door.",
            "ua": "Otworzyła drzwi.",
            "note": "→ Passive: The door was opened. ✅"
        },
        {
            "en": "Intransitive: The door opened.",
            "ua": "Drzwi się otworzyły.",
            "note": "→ Pasywnie: ❌ (bez aplikacji)"
        }
    ],
    "warning": "📌 Niektóre czasowniki mogą być przechodnie i nieprzechodnie w zależności od kontekstu!"
}

{
    "title": "4. Czasowniki zwrotne",
    "sections": [
        {
            "label": "Odwrotne działania",
            "color": "rose",
            "description": "Kiedy podmiot i dopełnienie są <strong>takie same</strong>, strona bierna nie jest używana:",
            "examples": [
                {
                    "en": "She washed herself. ✅",
                    "ua": "(не: Została przez nią umyta. ❌)"
                },
                {
                    "en": "He hurt himself. ✅",
                    "ua": "(не: Sam został przez niego zraniony. ❌)"
                },
                {
                    "en": "They enjoyed themselves. ✅",
                    "ua": "(bez pasywnego)"
                }
            ]
        },
        {
            "label": "Wzajemne działania",
            "color": "blue",
            "description": "Kiedy działanie jest <strong>wzajemne</strong> (wzajemnie):",
            "examples": [
                {
                    "en": "They love each other. ✅",
                    "ua": "(не: Są przez nich kochani. ❌)"
                },
                {
                    "en": "We helped each other. ✅",
                    "ua": "(bez pasywnego)"
                },
                {
                    "en": "They met each other. ✅",
                    "ua": "(bez pasywnego)"
                }
            ]
        }
    ]
}

{
    "title": "5. Inne ograniczenia",
    "intro": "Niektóre konstrukcje i znaczenia ograniczają stronę bierną:",
    "items": [
        {
            "label": "Pokrewne obiekty",
            "title": "powiązane aplikacje",
            "subtitle": "żyj szczęśliwym życiem, śnij marzenia – bez strony biernej"
        },
        {
            "label": "Frazeologia",
            "title": "wyrażenia stałe",
            "subtitle": "miej oko – zwykle aktywny"
        },
        {
            "label": "uzyskać + przym",
            "title": "zmiana stanu",
            "subtitle": "złość się, zmęczenie NIE jest bierne"
        },
        {
            "label": "pozwalać",
            "title": "umożliwić",
            "subtitle": "Puścił mnie. → Pozwolono mi odejść. (не: pozwolono)"
        }
    ]
}

{
    "title": "6. Czasowniki o podwójnym znaczeniu",
    "intro": "Niektóre czasowniki mają znaczenie przechodnie i nieprzechodnie:",
    "rows": [
        {
            "en": "run (transitive): They run a business.",
            "ua": "Prowadzą firmę.",
            "note": "→ A business is run by them. ✅"
        },
        {
            "en": "run (intransitive): He runs every day.",
            "ua": "Biega codziennie.",
            "note": "→ ❌ (bez pasywnego)"
        },
        {
            "en": "grow (transitive): They grow vegetables.",
            "ua": "Uprawiają warzywa.",
            "note": "→ Vegetables are grown. ✅"
        },
        {
            "en": "grow (intransitive): Children grow fast.",
            "ua": "Dzieci szybko rosną.",
            "note": "→ ❌ (bez pasywnego)"
        }
    ],
    "warning": "📌 Zanim utworzysz stronę bierną, sprawdź, czy czasownik ma dopełnienie bezpośrednie!"
}

{
    "title": "7. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Strona bierna czasownika nieprzechodniego.",
            "wrong": "The accident was happened yesterday.",
            "right": "✅ The accident happened yesterday."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Strona bierna czasowników posiadających.",
            "wrong": "A nice house is had by her.",
            "right": "✅ She has a nice house."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Strona bierna czasownika zwrotnego.",
            "wrong": "Himself was cut by him.",
            "right": "✅ He cut himself."
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Zamieszanie przechodnie/nieprzechodnie.",
            "wrong": "He was arrived late.",
            "right": "✅ He arrived late."
        }
    ]
}
